#include <stdio.h>
#include <stdlib.h>

int cmp_int(const void *a, const void *b) {
    long long va = *(const long long *)a;
    long long vb = *(const long long *)b;
    return (va > vb) - (va < vb);
}

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        long long *boys = (long long*)malloc(N * sizeof(long long));
        long long *girls = (long long*)malloc(N * sizeof(long long));
        for (int i = 0; i < N; ++i) scanf("%lld", &boys[i]);
        for (int i = 0; i < N; ++i) scanf("%lld", &girls[i]);
        qsort(boys, N, sizeof(long long), cmp_int);
        qsort(girls, N, sizeof(long long), cmp_int);
        long long ans = 0;
        for (int i = 0; i < N; ++i) {
            long long sum = boys[i] + girls[N-1-i];
            if (sum > ans) ans = sum;
        }
        printf("%lld\n", ans);
        free(boys);
        free(girls);
    }
    return 0;
}

